## Code Example

```javascript
// Example: assume cross-account role and write a marker to shared S3
const { STSClient, AssumeRoleCommand } = require("@aws-sdk/client-sts");
const { S3Client, PutObjectCommand } = require("@aws-sdk/client-s3");

async function testAccess(roleArn, bucket, key, body) {
  const sts = new STSClient({});
  const r = await sts.send(new AssumeRoleCommand({ RoleArn: roleArn, RoleSessionName: "AuditTest" }));
  const s3 = new S3Client({ credentials: {
    accessKeyId: r.Credentials.AccessKeyId,
    secretAccessKey: r.Credentials.SecretAccessKey,
    sessionToken: r.Credentials.SessionToken
  }});
  await s3.send(new PutObjectCommand({ Bucket: bucket, Key: key, Body: body }));
}
```

