// Pseudo-code: fetch flag for tenant with caching
async function fetchFlag(tenantId, flagName) {
  // Retrieve from AppConfig with tenant scoping
  const config = await appconfig.getConfiguration(
    `tenant-${tenantId}`, 
    flagName
  );

  // Cache in DynamoDB for sub-millisecond access
  await dynamodb.put({
    TableName: 'feature-flags',
    Item: {
      tenantId,
      flagName,
      value: config.value,
      ttl: Date.now() + 30000 // 30s TTL
    }
  });

  return config.value;
}
```

