## Code Example
```javascript
const AWS = require('aws-sdk');
const s3 = new AWS.S3();
const ddb = new AWS.DynamoDB.DocumentClient();

exports.handler = async (event) => {
  const bucket = event.Records[0].s3.bucket.name;
  const key = event.Records[0].s3.object.key;
  const obj = await s3.getObject({ Bucket: bucket, Key: key }).promise();
  const lines = obj.Body.toString('utf-8').split('\n');
  for (const line of lines) {
    if (!line.trim()) continue;
    const [transactionId, data] = line.split(',');
    // dedupe check
    const exists = await ddb.get({
      TableName: 'ProcessedTransactions',
      Key: { transactionId }
    }).promise();
    if (exists.Item) continue;
    // write primary record
    await ddb.put({ TableName: 'VendorRecords', Item: { transactionId, data } }).promise();
    await ddb.put({ TableName: 'ProcessedTransactions', Item: { transactionId } }).promise();
  }
  return 'done';
};
```

