## Code Example

```javascript
// Idempotent job processor with retry logic
async function processJob(message) {
  const { jobId, idempotencyKey, attempt = 1 } = JSON.parse(message.Body);

  try {
    const result = await dynamoDB.update({
      TableName: 'Jobs',
      Key: { pk: `REGION#${region}`, sk: `JOB#${jobId}` },
      UpdateExpression: 'SET #state = :processing, version = version + :inc',
      ConditionExpression: '(attribute_not_exists(#state) OR #state = :pending) AND idempotencyKey = :ikey',
      ExpressionAttributeNames: { '#state': 'state' },
      ExpressionAttributeValues: {
        ':processing': 'PROCESSING', ':pending': 'PENDING',
        ':inc': 1, ':ikey': idempotencyKey
      }
    }).promise();

    await doWork(jobId);
    await completeJob(jobId);
    sqs.deleteMessage({ QueueUrl, ReceiptHandle: message.ReceiptHandle });
  } catch (e) {
    if (e.code === 'ConditionalCheckFailedException') {
      console.log('Job already processed or in unexpected state');
      sqs.deleteMessage({ QueueUrl, ReceiptHandle: message.ReceiptHandle });
    } else if (attempt < 3) {
      sqs.changeMessageVisibility({ QueueUrl, ReceiptHandle: message.ReceiptHandle, VisibilityTimeout: 0 });
    } else {
      sqs.moveMessageToDlq({ QueueUrl, ReceiptHandle: message.ReceiptHandle });
    }
  }
}
```

